class Solution:
    def clearDigits(self, s: str) -> str:
        s = list(s)
        i = 0
        while i < len(s):
            if s[i].isdigit():
                # Find the closest non-digit to the left
                j = i - 1
                while j >= 0 and s[j].isdigit():
                    j -= 1
                if j >= 0:
                    del s[j]
                    del s[i - 1]
                    i = 0  # Reset index to start from beginning
                else:
                    # No non-digit to the left, so delete the digit
                    del s[i]
                    i = 0
            else:
                i += 1
        return ''.join(s)
